import{_ as t,o as r,c as e,a1 as o}from"./chunks/framework.BX4nIuL2.js";const p=JSON.parse('{"title":"Fab 数字化快速原型课程","description":"","frontmatter":{},"headers":[],"relativePath":"courses/fab-course.md","filePath":"courses/fab-course.md"}'),i={name:"courses/fab-course.md"};function s(n,a,l,c,u,d){return r(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="fab-数字化快速原型课程" tabindex="-1">Fab 数字化快速原型课程 <a class="header-anchor" href="#fab-数字化快速原型课程" aria-label="Permalink to &quot;Fab 数字化快速原型课程&quot;">​</a></h1><p>数字化快速原型技术（Rapid Prototyping）是将 AI 生成的硬件创意具象化为物理实体的桥梁。本课程带您走进 Fab Lab (数字化制造实验室)，熟练掌握各类微型数字制造设备的安全操作与设计规范。</p><h2 id="_1-3d-打印工艺与材料-3d-printing" tabindex="-1">1. 3D 打印工艺与材料 (3D Printing) <a class="header-anchor" href="#_1-3d-打印工艺与材料-3d-printing" aria-label="Permalink to &quot;1. 3D 打印工艺与材料 (3D Printing)&quot;">​</a></h2><p>3D 打印（增材制造）是快速验证外观结构与组装公差的最佳手段。</p><ul><li><strong>FDM 熔融沉积:</strong> 常用材料为 PLA、PETG 及 ABS。打印外壳时建议壁厚不小于 1.6mm。</li><li><strong>SLA 光固化:</strong> 适用于高精度机械结构与按钮件，表面质量极高但强度相对较脆。</li></ul><h2 id="_2-激光切割与雕刻-laser-cutting" tabindex="-1">2. 激光切割与雕刻 (Laser Cutting) <a class="header-anchor" href="#_2-激光切割与雕刻-laser-cutting" aria-label="Permalink to &quot;2. 激光切割与雕刻 (Laser Cutting)&quot;">​</a></h2><p>激光切割（减材制造）可快速加工薄板件，如压克力、椴木板以及薄皮套。</p><ul><li><strong>排版规范:</strong> 红色线条表示切割（Cut），黑色填充表示扫描雕刻（Engrave）。</li><li><strong>缝隙补偿 (Kerf):</strong> 切割时激光束具有一定宽度（通常为 0.1mm - 0.2mm），设计榫卯拼接时需考虑过盈配合。</li></ul><hr><h2 id="_3-研讨与答疑" tabindex="-1">3. 研讨与答疑 <a class="header-anchor" href="#_3-研讨与答疑" aria-label="Permalink to &quot;3. 研讨与答疑&quot;">​</a></h2><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>划词对任意打印参数进行评论，我们的指导教师将会在评论区解答关于热床温度、层高设定以及支撑结构生成的疑问。</p></div>',11)])])}const h=t(i,[["render",s]]);export{p as __pageData,h as default};
